"""
stream.py — Streaming Ingestion Adapter

Accepts a continuous stream of (chunk_id, amplitude, frequency) tuples,
buffers them in memory, and flushes to a PrismResonance instance when:
  - the buffer reaches `max_buffer_size`, OR
  - `flush_interval` seconds have elapsed since the last flush

This decouples fast producers (e.g., log ingestors, event streams) from
the PrismResonance ingest path, which may be slower due to ONNX setup.

Usage
-----
::

    from prismresonance.stream import StreamIngester
    from prismresonance import PrismResonance
    from prismresonance.frequency import FrequencyFamily

    prism = PrismResonance.create(embedding_dim=3072)
    ingester = StreamIngester(prism, max_buffer_size=50, flush_interval=5.0)
    ingester.start()

    # Producer thread
    ingester.push("chunk_001", amplitude_vec, FrequencyFamily.ALERT)
    ingester.push("chunk_002", amplitude_vec, FrequencyFamily.EMERGENCY)

    # On shutdown
    ingester.stop()   # flushes remaining buffer before stopping
"""

from __future__ import annotations

import logging
import threading
import time
from dataclasses import dataclass
from typing import List, Optional, Tuple

import numpy as np

from .frequency import FrequencyFamily

log = logging.getLogger("prismresonance.stream")


# ─────────────────────────────────────────────────────────────────────────────
# Buffer entry
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class _BufferEntry:
    chunk_id: str
    amplitude: np.ndarray
    frequency: float
    parent_id: Optional[str]


# ─────────────────────────────────────────────────────────────────────────────
# StreamIngester
# ─────────────────────────────────────────────────────────────────────────────

class StreamIngester:
    """
    Buffered streaming ingestion adapter for PrismResonance.

    Thread-safe: `push()` can be called from any thread.
    A background thread flushes the buffer on size or time triggers.

    Parameters
    ----------
    prism           : A PrismResonance instance to flush chunks into.
    max_buffer_size : Flush when this many chunks are buffered.
    flush_interval  : Flush at least every this many seconds.
    """

    def __init__(
        self,
        prism,                         # PrismResonance — avoid circular import
        max_buffer_size: int = 100,
        flush_interval: float = 5.0,
    ) -> None:
        self._prism          = prism
        self._max_buffer     = max_buffer_size
        self._flush_interval = flush_interval

        self._buffer: List[_BufferEntry] = []
        self._lock   = threading.Lock()
        self._stop   = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._last_flush = time.time()

        # Stats
        self._total_pushed  = 0
        self._total_flushed = 0

    # ── Public API ────────────────────────────────────────────────────────

    def start(self) -> None:
        """Start the background flush thread."""
        if self._thread and self._thread.is_alive():
            return
        self._stop.clear()
        self._thread = threading.Thread(
            target=self._loop,
            name="prismresonance-stream",
            daemon=True,
        )
        self._thread.start()
        log.info(
            "StreamIngester started (buffer=%d, interval=%.1fs)",
            self._max_buffer, self._flush_interval,
        )

    def stop(self) -> None:
        """Stop the background thread and flush any remaining buffer."""
        self._stop.set()
        if self._thread:
            self._thread.join(timeout=10)
        self._flush()
        log.info(
            "StreamIngester stopped (pushed=%d, flushed=%d)",
            self._total_pushed, self._total_flushed,
        )

    def push(
        self,
        chunk_id: str,
        amplitude: np.ndarray,
        frequency: FrequencyFamily | float = FrequencyFamily.NEUTRAL,
        parent_id: Optional[str] = None,
    ) -> None:
        """
        Add a chunk to the ingestion buffer.

        Thread-safe. Triggers an immediate flush if the buffer is full.

        Parameters
        ----------
        chunk_id  : Unique identifier for this chunk.
        amplitude : (N,) float32 embedding from upstream encoder.
        frequency : Operational context to assign to this chunk.
        parent_id : Optional trigger chunk that caused this chunk's creation.
        """
        entry = _BufferEntry(
            chunk_id=chunk_id,
            amplitude=amplitude,
            frequency=float(frequency),
            parent_id=parent_id,
        )
        with self._lock:
            self._buffer.append(entry)
            self._total_pushed += 1
            should_flush = len(self._buffer) >= self._max_buffer

        if should_flush:
            self._flush()

    def flush(self) -> int:
        """
        Manually trigger a buffer flush.

        Returns the number of chunks flushed.
        """
        return self._flush()

    @property
    def buffer_size(self) -> int:
        """Current number of buffered chunks waiting to be flushed."""
        with self._lock:
            return len(self._buffer)

    @property
    def stats(self) -> dict:
        return {
            "total_pushed":  self._total_pushed,
            "total_flushed": self._total_flushed,
            "buffer_size":   self.buffer_size,
        }

    # ── Internal ──────────────────────────────────────────────────────────

    def _loop(self) -> None:
        while not self._stop.wait(timeout=self._flush_interval):
            try:
                self._flush()
            except Exception:
                log.exception("StreamIngester: error during flush")

    def _flush(self) -> int:
        with self._lock:
            if not self._buffer:
                return 0
            batch = self._buffer[:]
            self._buffer.clear()

        count = 0
        for entry in batch:
            try:
                self._prism.ingest(
                    chunk_id=entry.chunk_id,
                    amplitude=entry.amplitude,
                    frequency=entry.frequency,
                    parent_id=entry.parent_id,
                )
                count += 1
            except Exception:
                log.exception("StreamIngester: failed to ingest chunk %s", entry.chunk_id)

        self._total_flushed += count
        self._last_flush = time.time()

        if count:
            log.debug("StreamIngester flushed %d chunks", count)

        return count
